// Extrae datos del mensaje entrante de WhatsApp
const body = $input.first().json;
const entry = body.entry?.[0];
const change = entry?.changes?.[0];
const message = change?.value?.messages?.[0];
const contact = change?.value?.contacts?.[0];

if (!message) {
  return [{ json: { skip: true } }];
}

return [{
  json: {
    from: message.from,           // Número del cliente
    name: contact?.profile?.name || 'Cliente',
    messageId: message.id,
    type: message.type,           // text, interactive, etc.
    text: message.text?.body || '',
    timestamp: message.timestamp
  }
}];

// Detecta si el mensaje es una selección del menú (número del 1 al 6)
const text = $input.first().json.text.trim();
const seleccion = parseInt(text);

const MENU = {
  1: { nombre: 'Combo Clásico', precio: 5.50, ingredientes: { carne: 150, pan: 1, papa: 200, refresco: 1 } },
  2: { nombre: 'Combo Doble', precio: 7.50, ingredientes: { carne: 300, pan: 1, papa: 200, refresco: 1 } },
  3: { nombre: 'Combo Pollo', precio: 6.00, ingredientes: { pollo: 180, pan: 1, papa: 200, refresco: 1 } },
  4: { nombre: 'Papas fritas', precio: 1.50, ingredientes: { papa: 150 } },
  5: { nombre: 'Refresco', precio: 1.00, ingredientes: { refresco: 1 } },
  6: { nombre: 'Agua', precio: 0.75, ingredientes: { agua: 1 } },
};

if (seleccion >= 1 && seleccion <= 6) {
  const item = MENU[seleccion];
  const numeroPedido = 'WA-' + Date.now().toString().slice(-6);
  return [{
    json: {
      ...($input.first().json),
      pedido: {
        numero: numeroPedido,
        items: [item],
        total: item.precio,
        estado: 'RECIBIDO',
        canal: 'WHATSAPP',
        timestamp: new Date().toISOString()
      },
      esSeleccionValida: true
    }
  }];
}

return [{ json: { ...($input.first().json), esSeleccionValida: false } }];

